-- ============================================================
-- LIMINARES (cruzado com Apoio) e APOIO PEDAGÓGICO
-- Professores de apoio = Manhã + Tarde | Apoios = ASSEJ
-- Liminar Atendida = unidade municipal COM apoio; senão Pendência; particular/estadual = Fora da rede
-- Rode no SQL Editor (Mapa/main): Ctrl+A -> Ctrl+Enter.
-- ============================================================
DROP TABLE IF EXISTS ee_liminar_escola CASCADE;
DROP TABLE IF EXISTS ee_liminar_aluno CASCADE;
DROP TABLE IF EXISTS ee_liminar_unidade CASCADE;
DROP TABLE IF EXISTS ee_apoio CASCADE;

CREATE TABLE ee_apoio (id serial PRIMARY KEY, tipo text, escola text, professores int, apoios int);
ALTER TABLE ee_apoio DISABLE ROW LEVEL SECURITY;
CREATE TABLE ee_liminar_aluno (id serial PRIMARY KEY, aluno text, ra text, escola text, turma text, deficiencia text, status text);
ALTER TABLE ee_liminar_aluno DISABLE ROW LEVEL SECURITY;
CREATE TABLE ee_liminar_unidade (id serial PRIMARY KEY, escola text, tipo text, alunos int, professores int, apoios int, status text);
ALTER TABLE ee_liminar_unidade DISABLE ROW LEVEL SECURITY;


CREATE OR REPLACE FUNCTION ee_apoio() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$
  SELECT json_build_object(
    'geral',(SELECT json_build_object('escolas',count(*),'professores',coalesce(sum(professores),0),'apoios',coalesce(sum(apoios),0)) FROM ee_apoio),
    'escolas',coalesce((SELECT json_agg(json_build_array(tipo,escola,professores,apoios)) FROM (SELECT * FROM ee_apoio ORDER BY tipo,escola) s),'[]'::json)
  );
$$;
CREATE OR REPLACE FUNCTION ee_liminar() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$
  SELECT json_build_object(
    'geral',(SELECT json_build_object(
       'alunos',(SELECT count(*) FROM ee_liminar_aluno),
       'unidades',(SELECT count(*) FROM ee_liminar_unidade),
       'atendidas',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Atendida'),
       'pendentes',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Pendência'),
       'fora',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Fora da rede municipal'),
       'alunos_pend',(SELECT count(*) FROM ee_liminar_aluno WHERE status='Pendência'))),
    'unidades',coalesce((SELECT json_agg(json_build_array(escola,tipo,alunos,professores,apoios,status)) FROM (SELECT * FROM ee_liminar_unidade ORDER BY status,escola) s),'[]'::json),
    'alunos',coalesce((SELECT json_agg(json_build_array(aluno,ra,escola,turma,deficiencia,status)) FROM (SELECT * FROM ee_liminar_aluno ORDER BY escola,aluno) s),'[]'::json)
  );
$$;
GRANT SELECT ON ee_apoio, ee_liminar_aluno, ee_liminar_unidade TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_apoio() TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_liminar() TO anon, authenticated;
